```typescript
// @/src/hooks/useNotification.hooks.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationProps } from '../helpers/notification.helpers';

const NotificationContext = createContext(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notification, setNotification] = useState(null);

  useEffect(() => {
    if (notificationElem) {
      setNotification(notificationElem);
    }
  }, [notificationElem]);

  const notify = async (props: NotificationProps) => {
    if (!notification) return;

    const { heading, subheading, type } = props;
    await notification.open({
      heading,
      subheading,
      type,
    });
  };

  return { notify };
};

export default useNotification;
